import 'package:graduway/alumni/shared/providers/mentorship_provider.dart';
import 'package:graduway/models/user_role.dart';

import 'dart:async';
import 'package:flutter/material.dart';
import 'package:graduway/alumni/shared/models/mentorship_model.dart';
import 'package:graduway/student/shared/services/mentorship_service.dart';
import 'package:graduway/student/shared/services/persistence_service.dart';
import 'package:graduway/student/shared/services/classroom_service.dart';
import 'package:graduway/alumni/shared/providers/auth_provider.dart';
import 'package:graduway/alumni/shared/providers/chat_provider.dart';

/// Manages the state of mentorship requests and sessions. class MentorshipProvider with ChangeNotifier {   final MentorshipService _service = MentorshipService();   final PersistenceService _persistence = PersistenceService();   final ClassroomService _classroomService = ClassroomService();   ChatProvider? _chatProvider;   AuthProvider? _AuthProvider;   StreamSubscription? _subscription;    bool _isLoading = false;   String? _error;    /// Whether a mentorship operation is currently in progress.   bool get isLoading => _isLoading;    /// The latest error encountered during mentorship operations.   String? get error => _error;      List<MentorshipRequest> _allRequests = [];   List<Map<String, dynamic>> _webinars = [];    /// Returns a list of all mentorship requests.   List<MentorshipRequest> get allRequests => _allRequests;    /// Returns current and upcoming webinars/classes.   List<Map<String, dynamic>> get webinars => _webinars;    /// Sets the [ChatProvider] instance to be used for creating chat sessions.   void setChatProvider(ChatProvider chatProvider) {     _chatProvider = chatProvider;   }    /// Syncs with [AuthProvider] to fetch identity-specific data.   void syncWithAuth(AuthProvider auth) {     bool userIdChanged = _AuthProvider?.userId != auth.userId;     _AuthProvider = auth;          if (userIdChanged && auth.userId != null) {       _fetchLiveData();     }   }    Future<void> _fetchLiveData() async {     if (_AuthProvider == null || _AuthProvider!.userId == null) return;          _isLoading = true;     notifyListeners();      try {       if (_AuthProvider!.role == UserRole.mentor) {         await _service.fetchRequests(mentorId: _AuthProvider!.userId);       } else {         await _service.fetchRequests(studentId: _AuthProvider!.userId);       }       _allRequests = _service.getRequests();       await saveToLocal();     } catch (e) {       _error = e.toString();     } finally {       _isLoading = false;       notifyListeners();     }   }      MentorshipProvider() {     _init();   }    /// Initializes the provider by loading data from local storage or seeding for demo.   Future<void> _init() async {     _isLoading = true;     notifyListeners();      // 1. Sync Room List via Signaling Server     _classroomService.onRoomListUpdate = (roomData) {       _webinars = roomData.map((r) => {         'id': r['id'],         'title': r['title'],         'startTime': r['startTime'],         'isLive': r['isLive'],         'attendees': r['attendees'],       }).toList();       notifyListeners();     };      // Connect to signaling server to get updates (Student view)     _classroomService.joinRoom(       serverUrl: AuthProvider.getSignalingUrl(),       roomId: 'global-lobby',       userName: 'Discovery-User', // Background lobby join doesn't need personal identity       role: ClassroomRole.student,       useMedia: false, // Don't start cam just for the room list updates     );      // 2. Load mentorship requests (Initial load from local, then sync with auth)     await loadFromLocal();     if (_AuthProvider?.userId != null) {       await _fetchLiveData();     }          _subscription = _service.requestsStream.listen((updatedRequests) {       _allRequests = updatedRequests;       saveToLocal();       notifyListeners();     });      _isLoading = false;     notifyListeners();   }    /// Persists the current list of mentorship requests to local storage.   Future<void> saveToLocal() async {     final data = _allRequests.map((r) => r.toJson()).toList();     await _persistence.saveData('mentorship_requests', data);   }    /// Loads mentorship requests from local storage.   Future<void> loadFromLocal() async {     final data = await _persistence.getData('mentorship_requests');     if (data != null && data is List) {       _allRequests = data.map((json) => MentorshipRequest.fromJson(json)).toList();       notifyListeners();     }   }    /// Returns a list of requests that are currently in the 'pending' status.   List<MentorshipRequest> get pendingRequests =>        _allRequests.where((r) => r.status == MentorshipStatus.pending).toList();    /// Returns a list of mentees whose requests have been 'accepted'.   List<MentorshipRequest> get acceptedMentees =>        _allRequests.where((r) => r.status == MentorshipStatus.accepted).toList();    /// The count of pending mentorship requests.   int get pendingCount => pendingRequests.length;    /// The count of accepted mentorship sessions.   int get acceptedCount => acceptedMentees.length;    /// Accepts a mentorship request by ID and creates a corresponding chat session.   Future<void> acceptRequest(String id) async {     _isLoading = true;     _error = null;     notifyListeners();      try {       final request = _allRequests.firstWhere((r) => r.id == id);       await _service.updateRequestStatus(id, MentorshipStatus.accepted);              if (_chatProvider != null) {         _chatProvider!.createSession(request.student);       }       await saveToLocal();     } catch (e) {       _error = e.toString();     } finally {       _isLoading = false;       notifyListeners();     }   }    /// Rejects a mentorship request by ID.   Future<void> rejectRequest(String id) async {     _isLoading = true;     _error = null;     notifyListeners();     try {       await _service.updateRequestStatus(id, MentorshipStatus.rejected);       await saveToLocal();     } catch (e) {       _error = e.toString();     } finally {       _isLoading = false;       notifyListeners();     }   }    /// Starts a new webinar session.   void startNewWebinar(String title) {     // This will emit to the server via joinRoom when the mentor actually enters the page     notifyListeners();   }    @override   void dispose() {     _subscription?.cancel();     _classroomService.dispose();     super.dispose();   } }

